func chatBubbleContainerClass(role string) string {
	switch role {
	case "user":
		return "flex justify-end px-4 py-1.5"
	case "assistant":
		return "flex justify-start px-4 py-1.5"
	default:
		return "flex justify-center px-4 py-1"
	}
}

func chatBubbleClass(role string) string {
	switch role {
	case "user":
		return "bg-muted/70 border border-border rounded-2xl rounded-br-md px-4 py-3 max-w-[80%]"
	case "assistant":
		return "bg-primary/5 border border-primary/20 rounded-2xl rounded-bl-md px-4 py-3 max-w-[80%]"
	case "system":
		return "bg-muted/30 border border-border rounded-lg px-3 py-2 text-xs text-muted-foreground max-w-[60%]"
	default:
		return "bg-muted/50 border border-border rounded-2xl px-4 py-3 max-w-[80%]"
	}
}

